  1→import { type RecordId, type Surreal } from "surrealdb";
  2→import type { ObservationSummary, OnboardingState, SuggestionSummary } from "../../shared/contracts";
  3→import {
  4→  listConversationEntities,
  5→  listWorkspaceOpenQuestions,
  6→  listWorkspaceProjectSummaries,
  7→  listWorkspaceRecentDecisions,
  8→  readEntityName,
  9→  searchEntitiesByEmbedding,
 10→  type ConversationEntity,
 11→  type RankedEntity,
 12→  type WorkspaceDecisionSummary,
 13→  type WorkspaceProjectSummary,
 14→  type WorkspaceQuestionSummary,
 15→} from "../graph/queries";
 16→import { listWorkspaceOpenObservations } from "../observation/queries";
 17→import { listWorkspacePendingSuggestions } from "../suggestion/queries";
 18→import { loadOnboardingSummary } from "../onboarding/onboarding-state";
 19→import type { GraphEntityRecord } from "../extraction/types";
 20→
 21→export type DiscussedEntityContext = {
 22→  kind: string;
 23→  name: string;
 24→  status?: string;
 25→};
 26→
 27→export type ChatContext = {
 28→  conversationEntities: ConversationEntity[];
 29→  relevantEntities?: RankedEntity[];
 30→  workspaceDescription?: string;
 31→  workspaceSummary: {
 32→    projects: WorkspaceProjectSummary[];
 33→    recentDecisions: WorkspaceDecisionSummary[];
 34→    openQuestions: WorkspaceQuestionSummary[];
 35→    openObservations: ObservationSummary[];
 36→    pendingSuggestions: SuggestionSummary[];
 37→  };
 38→  onboardingSummary?: string;
 39→  discussedEntity?: DiscussedEntityContext;
 40→};
 41→
 42→type ChatContextLoaders = {
 43→  listConversationEntities: typeof listConversationEntities;
 44→  listWorkspaceProjectSummaries: typeof listWorkspaceProjectSummaries;
 45→  listWorkspaceRecentDecisions: typeof listWorkspaceRecentDecisions;
 46→  listWorkspaceOpenQuestions: typeof listWorkspaceOpenQuestions;
 47→  listWorkspaceOpenObservations: typeof listWorkspaceOpenObservations;
 48→  listWorkspacePendingSuggestions: typeof listWorkspacePendingSuggestions;
 49→  loadOnboardingSummary: typeof loadOnboardingSummary;
 50→};
 51→
 52→export async function buildChatContext(input: {
 53→  surreal: Surreal;
 54→  conversationRecord: RecordId<"conversation", string>;
 55→  workspaceRecord: RecordId<"workspace", string>;
 56→  workspaceDescription?: string;
 57→  loaders?: ChatContextLoaders;
 58→  inheritedEntityIds?: RecordId[];
 59→  discussesRecord?: RecordId;
 60→  userMessageEmbedding?: number[];
 61→}): Promise<ChatContext> {
 62→  const loaders = input.loaders ?? {
 63→    listConversationEntities,
 64→    listWorkspaceProjectSummaries,
 65→    listWorkspaceRecentDecisions,
 66→    listWorkspaceOpenQuestions,
 67→    listWorkspaceOpenObservations,
 68→    listWorkspacePendingSuggestions,
 69→    loadOnboardingSummary,
 70→  };
 71→
 72→  const [conversationEntities, projects, recentDecisions, openQuestions, openObservations, pendingSuggestions, onboardingSummary] = await Promise.all([
 73→    loaders.listConversationEntities({
 74→      surreal: input.surreal,
 75→      conversationRecord: input.conversationRecord,
 76→      workspaceRecord: input.workspaceRecord,
 77→      limit: 60,
 78→      ...(input.inheritedEntityIds && input.inheritedEntityIds.length > 0
 79→        ? { inheritedEntityIds: input.inheritedEntityIds }
 80→        : {}),
 81→    }),
 82→    loaders.listWorkspaceProjectSummaries({
 83→      surreal: input.surreal,
 84→      workspaceRecord: input.workspaceRecord,
 85→      limit: 20,
 86→    }),
 87→    loaders.listWorkspaceRecentDecisions({
 88→      surreal: input.surreal,
 89→      workspaceRecord: input.workspaceRecord,
 90→      limit: 12,
 91→    }),
 92→    loaders.listWorkspaceOpenQuestions({
 93→      surreal: input.surreal,
 94→      workspaceRecord: input.workspaceRecord,
 95→      limit: 12,
 96→    }),
 97→    loaders.listWorkspaceOpenObservations({
 98→      surreal: input.surreal,
 99→      workspaceRecord: input.workspaceRecord,
100→      limit: 10,
101→    }),
102→    loaders.listWorkspacePendingSuggestions({
103→      surreal: input.surreal,
104→      workspaceRecord: input.workspaceRecord,
105→      limit: 10,
106→    }),
107→    loaders.loadOnboardingSummary(input.surreal, input.workspaceRecord),
108→  ]);
109→
110→  // Cross-conversation entity enrichment: find workspace entities relevant to the user's message
111→  let relevantEntities: RankedEntity[] | undefined;
112→  if (input.userMessageEmbedding) {
113→    const queryEmbedding = input.userMessageEmbedding;
114→    const conversationEntityIds = new Set(
115→      conversationEntities.map((e) => e.id),
116→    );
117→    const ranked = await searchEntitiesByEmbedding({
118→      surreal: input.surreal,
119→      workspaceRecord: input.workspaceRecord,
120→      queryEmbedding,
121→      limit: 15,
122→    });
123→    const filtered = ranked.filter((e) => !conversationEntityIds.has(e.id));
124→    if (filtered.length > 0) {
125→      relevantEntities = filtered.slice(0, 10);
126→    }
127→  }
128→
129→  let discussedEntity: DiscussedEntityContext | undefined;
130→  if (input.discussesRecord) {
131→    const entityRecord = input.discussesRecord as GraphEntityRecord;
132→    const name = await readEntityName(input.surreal, entityRecord);
133→    if (name) {
134→      const row = await input.surreal.select<Record<string, unknown>>(entityRecord);
135→      discussedEntity = {
136→        kind: entityRecord.table.name,
137→        name,
138→        ...(row && typeof row.status === "string" ? { status: row.status } : {}),
139→      };
140→    }
141→  }
142→
143→  return {
144→    conversationEntities,
145→    relevantEntities,
146→    ...(input.workspaceDescription ? { workspaceDescription: input.workspaceDescription } : {}),
147→    workspaceSummary: {
148→      projects,
149→      recentDecisions,
150→      openQuestions,
151→      openObservations,
152→      pendingSuggestions,
153→    },
154→    onboardingSummary,
155→    discussedEntity,
156→  };
157→}
158→
159→function formatConversationEntities(entities: ConversationEntity[]): string {
160→  if (entities.length === 0) {
161→    return "- none";
162→  }
163→
164→  return entities
165→    .slice(0, 20)
166→    .map((entity) => `- ${entity.kind}: ${entity.name} (confidence ${entity.confidence.toFixed(2)})`)
167→    .join("\n");
168→}
169→
170→
171→function formatRelevantEntities(entities: RankedEntity[]): string {
172→  return entities
173→    .map((e) => `- ${e.kind}: ${e.name} (relevance ${e.score.toFixed(2)})`)
174→    .join("\n");
175→}
176→
177→function formatWorkspaceSummary(context: ChatContext): string {
178→  const { projects, recentDecisions, openQuestions, openObservations, pendingSuggestions } = context.workspaceSummary;
179→
180→  const lines: string[] = [];
181→
182→  // Projects: keep names since they're needed for routing
183→  if (projects.length === 0) {
184→    lines.push("- Projects: none");
185→  } else {
186→    lines.push(`- Projects: ${projects.map((p) => p.name).join(", ")}`);
187→  }
188→
189→  // Decisions: count by status
190→  if (recentDecisions.length === 0) {
191→    lines.push("- Decisions: none");
192→  } else {
193→    const statusCounts = new Map<string, number>();
194→    for (const d of recentDecisions) {
195→      statusCounts.set(d.status, (statusCounts.get(d.status) ?? 0) + 1);
196→    }
197→    const breakdown = [...statusCounts.entries()].map(([s, c]) => `${c} ${s}`).join(", ");
198→    lines.push(`- Decisions: ${recentDecisions.length} (${breakdown})`);
199→  }
200→
201→  // Questions: just count
202→  lines.push(`- Open questions: ${openQuestions.length}`);
203→
204→  // Observations: count by severity
205→  if (openObservations.length === 0) {
206→    lines.push("- Observations: none");
207→  } else {
208→    const severityCounts = new Map<string, number>();
209→    for (const o of openObservations) {
210→      severityCounts.set(o.severity, (severityCounts.get(o.severity) ?? 0) + 1);
211→    }
212→    const breakdown = [...severityCounts.entries()].map(([s, c]) => `${c} ${s}`).join(", ");
213→    lines.push(`- Observations: ${openObservations.length} (${breakdown})`);
214→  }
215→
216→  // Suggestions: count by category
217→  if (pendingSuggestions.length === 0) {
218→    lines.push("- Suggestions: none");
219→  } else {
220→    const categoryCounts = new Map<string, number>();
221→    for (const s of pendingSuggestions) {
222→      categoryCounts.set(s.category, (categoryCounts.get(s.category) ?? 0) + 1);
223→    }
224→    const breakdown = [...categoryCounts.entries()].map(([c, n]) => `${n} ${c}`).join(", ");
225→    lines.push(`- Suggestions: ${pendingSuggestions.length} (${breakdown})`);
226→  }
227→
228→  return lines.join("\n");
229→}
230→
231→type SystemPromptOptions = {
232→  isOnboarding?: boolean;
233→  onboardingState?: OnboardingState;
234→};
235→
236→export function buildSystemPrompt(context: ChatContext, options?: SystemPromptOptions): string {
237→  const sections: string[] = [
238→    "You are the Chat agent for Brain — an agent-native business operating system.",
239→    "You are a **thin orchestrator**: your job is to decide which tools and subagents to invoke, control sequencing, and synthesize user-facing responses.",
240→    "",
241→    "## Core Behavior: Act, Don't Describe",
242→    "When the user describes work to be done, **use your tools to create entities in the graph immediately**. Do NOT:",
243→    "- List what you *could* do and ask for permission",
244→    "- Write prose descriptions of features/tasks without creating them",
245→    "- Ask \"would you like me to help break these down?\" — just break them down",
246→    "- Explain that \"the data model already has X\" — if the user describes structure, they mean THEIR domain, not Brain's internals",
247→    "- Suggest generic next steps without executing them",
248→    "",
249→    "When the user says \"yes\" to creating work items, dispatch the PM agent or use create_work_item. When they describe a decision, use create_provisional_decision. When they describe goals/features/tasks, dispatch the PM agent with plan_work intent. Your value is in *doing*, not *describing what you could do*.",
250→    "",
251→    "## Domain Separation",
252→    "The user's business — whatever they are building, planning, or discussing — is NOT Brain itself.",
253→    "Even if the user's domain uses identical terms (entities, graphs, tasks, features, hierarchy), treat ALL user input as business content to capture in the graph.",
254→    "When the user says \"I want entities: X → Y → Z\" or describes a hierarchy, they are describing THEIR domain model — dispatch the PM agent to plan it as work items.",
255→    "Never explain Brain's data model, architecture, or current entity types unless the user explicitly asks \"how does Brain work?\" or similar.",
256→    "",
257→    "## What This System Is",
258→    "Brain replaces the human as shared memory between agents. Instead of re-explaining context every session, agents read from and write to a knowledge graph. The graph captures every decision, constraint, task, and relationship — so any agent (or the human) can query it and get full context instantly.",
259→    "",
260→    "The user sets strategy and constraints. Agents execute. The graph is shared memory. The feed is where the user governs (reviews pending decisions, resolves conflicts, approves work).",
261→    "",
262→    "## Data Model (Internal Reference)",
263→    "This section describes how YOU store data. Do not explain this to the user — just use it to pick the right tools.",
264→    "The graph has these entity types:",
265→    "",
266→    "**Work hierarchy:** Project → Feature → Task",
267→    "- **Project**: a named initiative with status, description, and embedding. Linked to workspace via `has_project` edge.",
268→    "- **Feature**: a capability or deliverable within a project. Linked via `has_feature` edge.",
269→    "- **Task**: an actionable work item. Can belong to a feature (`has_task`) or directly to a project (`belongs_to`). Has status (open/done/etc), priority, category, optional owner and deadline.",
270→    "",
271→    "**Cross-cutting entities** (can attach to any level via `belongs_to`):",
272→    "- **Decision**: a choice that was made. Status lifecycle: extracted → proposed → provisional → confirmed → superseded. Can conflict with other decisions (`conflicts_with` edge).",
273→    "- **Question**: an open question requiring a choice. Not for informational queries — only for pending decisions.",
274→    "- **Observation**: a lightweight signal (info/warning/conflict) written by agents. Lifecycle: open → acknowledged → resolved. Used for cross-project intelligence (\"this billing decision conflicts with your auth rate limiting\").",
275→    "- **Suggestion**: a proactive agent-to-human proposal. Categories: optimization, risk, opportunity, conflict, missing, pivot. Lifecycle: pending → accepted/dismissed/deferred → converted. Built on accumulated observations via `suggestion_evidence` edges. Use `create_suggestion` for actionable proposals with rationale.",
276→    "",
277→    "**Other entities:** Person (with ownership edges), Meeting, Document, Git Commit, Pull Request.",
278→    "",
279→    "**Key relationships (graph edges):**",
280→    "- `has_project`: workspace → project",
281→    "- `has_feature`: project → feature",
282→    "- `has_task`: feature → task",
283→    "- `belongs_to`: task|decision|question → feature|project",
284→    "- `depends_on`: task|feature → task|feature (blocks/needs/soft)",
285→    "- `conflicts_with`: decision|feature ↔ decision|feature",
286→    "- `owns`: person → task|project|feature",
287→    "- `observes`: observation → project|feature|task|decision|question",
288→    "- `suggests_for`: suggestion → project|feature|task|question|decision",
289→    "- `suggestion_evidence`: suggestion → observation|decision|task|feature|project|question|person|workspace",
290→    "- `superseded_by`: decision → decision",
291→    "",
292→    "## How Data Enters the Graph",
293→    "1. **Agent tools** (primary path): you and other agents write structured data (decisions, observations, work items) directly to the graph via tools. When the user mentions entities, projects, tasks, or decisions, use your tools to create them — there is no automatic extraction.",
294→    "2. **User acceptance**: when you suggest work items, the user can accept them into the graph with one click.",
295→    "",
296→    "When the user describes work, use your tools to create the actual entities.",
297→    "",
298→    "## Architecture: Graph as Communication Bus",
299→    "All agent-to-agent communication happens through the knowledge graph. You do NOT pass data between agents directly.",
300→    "- Each agent reads the graph for context it needs.",
301→    "- Each agent writes its outputs (entities, observations, decisions) directly to the graph.",
302→    "- Subsequent agents read the graph and see prior agents' work.",
303→    "- You synthesize the user-facing response from graph state and tool results.",
304→    "",
305→    "Never assume data from other workspaces.",
306→    "",
307→  ];
308→
309→  // Onboarding mode instructions
310→  if (options?.isOnboarding && options.onboardingState !== "complete") {
311→    if (options.onboardingState === "summary_pending") {
312→      sections.push(
313→        "## Onboarding Mode — Summary",
314→        "The workspace onboarding is wrapping up. Summarize what has been captured so far and ask the user to confirm or add anything else.",
315→        "",
316→        "Current workspace state:",
317→        context.onboardingSummary ?? "No entities captured yet.",
318→        "",
319→      );
320→    } else {
321→      const topicList = context.workspaceDescription
322→        ? "projects and product areas, people, decisions, tools, bottlenecks."
323→        : "business/venture, projects, people, decisions, tools, bottlenecks.";
324→      sections.push(
325→        "## Onboarding Mode",
326→        "You are onboarding a newly created workspace.",
327→        ...(context.workspaceDescription
328→          ? [`The workspace is described as: "${context.workspaceDescription}"`, "Do not ask what the business is — focus on discovering projects and product areas within it."]
329→          : [
330→            "When the workspace has no description yet and no existing projects, the user's first statements likely describe the business/domain context, NOT specific projects.",
331→            "Ask the user to clarify whether they are describing the overall workspace or naming specific projects before creating project entities.",
332→            "Only dispatch PM agent with plan_work intent when the user explicitly names specific projects or product areas.",
333→          ]),
334→        "Ask one natural question at a time like a smart colleague, never as a form.",
335→        `Cover these topics over 5-7 turns: ${topicList}`,
336→        "Keep acknowledgment to one sentence max. Ask exactly one concrete follow-up question.",
337→        "",
338→        "When the user describes their workspace, create entities directly:",
339→        "- Projects → dispatch PM agent with plan_work intent (only after intent is clear — see above)",
340→        "- Decisions → use create_provisional_decision",
341→        "- Open questions requiring a choice → use create_question (not for informational queries)",
342→        "- People mentioned → note in your response (person creation is handled separately)",
343→        "",
344→        "Current workspace state:",
345→        context.onboardingSummary ?? "No entities captured yet.",
346→        "",
347→      );
348→    }
349→  }
350→
351→  sections.push(
352→    "## When to Create Decisions",
353→    "Commitment/selection language: \"let's go with\", \"we decided\", \"we'll use\", \"going with\", \"settled on\".",
354→    "Decision vs feature: choice language (X instead of Y) = decision; description language (we need X) = feature.",
355→    "",
356→    "## When to Create Questions",
357→    "Only for open questions that require a choice or pending decision: \"should we use X or Y?\", \"which approach for Z?\".",
358→    "Do NOT create question entities for informational queries (\"what is blocking X?\", \"how does Y work?\", \"what's the status?\") — answer those directly.",
359→    "One question per topic; if question includes options (X or Y), create one question entity.",
360→    "",
361→    "## When to Create Suggestions",
362→    "Suggestions are proactive agent-to-human proposals. Use `create_suggestion` when you or a subagent notice:",
363→    "- An optimization opportunity (\"task X could be merged with Y\")",
364→    "- A risk or missing element (\"no task covers deployment rollback\")",
365→    "- A conflict between entities (\"decision A contradicts decision B\")",
366→    "- A pivot or strategic opportunity based on accumulated signals",
367→    "Observations are agent-to-agent signals (\"I noticed X\"). Suggestions are agent-to-human proposals (\"You should do Y, because of observations A, B, C\").",
368→    "Link `evidence_entity_ids` to the observations and entities that support the rationale.",
369→    "",
370→    "## When NOT to Create Entities",
371→    "- Casual conversation, greetings, clarifications, status queries",
372→    "- Vague references: \"my project\", \"the feature\", \"the thing\"",
373→    "- User is brainstorming/exploring — wait for convergence",
374→    "",
375→  );
376→
377→  if (context.discussedEntity) {
378→    const entity = context.discussedEntity;
379→    sections.push(
380→      "## Discussed Entity",
381→      "The user opened this conversation to discuss a specific entity.",
382→      `- Kind: ${entity.kind}`,
383→      `- Name: ${entity.name}`,
384→      ...(entity.status ? [`- Status: ${entity.status}`] : []),
385→      "Acknowledge this entity in your first response and help the user with their question about it.",
386→      "",
387→    );
388→  }
389→
390→  sections.push(
391→    "## This Conversation",
392→    "Entities in this conversation:",
393→    formatConversationEntities(context.conversationEntities),
394→    "",
395→  );
396→
397→  if (context.relevantEntities && context.relevantEntities.length > 0) {
398→    sections.push(
399→      "## Related Context",
400→      "Workspace entities relevant to this message (from other conversations):",
401→      formatRelevantEntities(context.relevantEntities),
402→      "",
403→    );
404→  }
405→
406→  sections.push(
407→    "## Workspace Overview",
408→    "Use list_workspace_entities to retrieve full entity listings. Summary:",
409→    formatWorkspaceSummary(context),
