  1→import { afterAll, beforeAll } from "bun:test";
  2→import { readFileSync } from "node:fs";
  3→import { join } from "node:path";
  4→import { Surreal } from "surrealdb";
  5→
  6→export type SmokeTestRuntime = {
  7→  baseUrl: string;
  8→  surreal: Surreal;
  9→  namespace: string;
 10→  database: string;
 11→  port: number;
 12→};
 13→
 14→const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
 15→const surrealUsername = process.env.SURREAL_USERNAME ?? "root";
 16→const surrealPassword = process.env.SURREAL_PASSWORD ?? "root";
 17→const smokePortBase = Number(process.env.SMOKE_PORT_BASE ?? "3100");
 18→
 19→export function setupSmokeSuite(suiteName: string): () => SmokeTestRuntime {
 20→  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
 21→  const namespace = `smoke_${runId}`;
 22→  const suiteSlug = suiteName
 23→    .toLowerCase()
 24→    .replace(/[^a-z0-9]+/g, "_")
 25→    .replace(/^_+|_+$/g, "");
 26→  const database = `${suiteSlug || "suite"}_${Math.floor(Math.random() * 100000)}`;
 27→
 28→  let runtime: SmokeTestRuntime | undefined;
 29→  let serverProcess: ReturnType<typeof Bun.spawn> | undefined;
 30→  let setupSucceeded = false;
 31→
 32→  beforeAll(async () => {
 33→    const port = process.env.SMOKE_PORT
 34→      ? Number(process.env.SMOKE_PORT)
 35→      : smokePortBase + Math.floor(Math.random() * 20000);
 36→    if (!Number.isFinite(port) || port <= 0) {
 37→      throw new Error(`Invalid smoke test port value: ${port}`);
 38→    }
 39→    const baseUrl = `http://127.0.0.1:${port}`;
 40→
 41→    const surreal = new Surreal();
 42→    await withTimeout(() => surreal.connect(surrealUrl), 10_000, "connect to SurrealDB");
 43→    await withTimeout(
 44→      () => surreal.signin({ username: surrealUsername, password: surrealPassword }),
 45→      10_000,
 46→      "authenticate with SurrealDB",
 47→    );
 48→
 49→    await withTimeout(() => surreal.query(`DEFINE NAMESPACE ${namespace};`), 10_000, "define test namespace");
 50→    await withTimeout(() => surreal.use({ namespace }), 10_000, "switch to test namespace");
 51→    await withTimeout(() => surreal.query(`DEFINE DATABASE ${database};`), 10_000, "define test database");
 52→    await withTimeout(
 53→      () => surreal.use({ namespace, database }),
 54→      10_000,
 55→      "switch to test namespace/database",
 56→    );
 57→
 58→    const schemaSql = readFileSync(join(process.cwd(), "schema", "surreal-schema.surql"), "utf8");
 59→    await withTimeout(() => surreal.query(schemaSql), 20_000, "apply schema");
 60→
 61→    serverProcess = Bun.spawn(["bun", "run", "app/server.ts"], {
 62→      cwd: process.cwd(),
 63→      env: {
 64→        ...process.env,
 65→        PORT: String(port),
 66→        SURREAL_NAMESPACE: namespace,
 67→        SURREAL_DATABASE: database,
 68→        BETTER_AUTH_URL: baseUrl,
 69→        BETTER_AUTH_SECRET: process.env.BETTER_AUTH_SECRET ?? "smoke-test-secret-at-least-32-chars-long",
 70→        GITHUB_CLIENT_ID: process.env.GITHUB_CLIENT_ID ?? "smoke-test-github-id",
 71→        GITHUB_CLIENT_SECRET: process.env.GITHUB_CLIENT_SECRET ?? "smoke-test-github-secret",
 72→      },
 73→      stdout: "pipe",
 74→      stderr: "inherit",
 75→    });
 76→
 77→    await waitForHealth(baseUrl, serverProcess, 15_000);
 78→    runtime = { baseUrl, surreal, namespace, database, port };
 79→    setupSucceeded = true;
 80→  }, 60_000);
 81→
 82→  afterAll(async () => {
 83→    if (serverProcess) {
 84→      serverProcess.kill();
 85→      await serverProcess.exited;
 86→    }
 87→
 88→    if (!runtime) {
 89→      return;
 90→    }
 91→
 92→    if (setupSucceeded && !process.env.SMOKE_KEEP_DB) {
 93→      try {
 94→        await withTimeout(() => runtime.surreal.query(`REMOVE DATABASE ${database};`), 10_000, "remove test database");
 95→      } catch {
 96→        // Best effort cleanup.
 97→      }
 98→
 99→      try {
100→        await withTimeout(() => runtime.surreal.query(`REMOVE NAMESPACE ${namespace};`), 10_000, "remove test namespace");
101→      } catch {
102→        // Best effort cleanup.
103→      }
104→    }
105→
106→    await withTimeout(() => runtime.surreal.close(), 2_000, "close SurrealDB").catch(() => undefined);
107→  }, 20_000);
108→
109→  return () => {
110→    if (!runtime) {
111→      throw new Error("Smoke runtime requested before suite setup completed");
112→    }
113→    return runtime;
114→  };
115→}
