144→export async function collectSseEvents<T extends { type: string }>(streamUrl: string, timeoutMs: number): Promise<T[]> {
145→  const response = await fetch(streamUrl, { headers: { Accept: "text/event-stream" } });
146→  if (!response.ok || !response.body) {
147→    throw new Error(`Failed to open SSE stream (${response.status})`);
148→  }
149→
150→  const reader = response.body.getReader();
151→  const decoder = new TextDecoder();
152→  const events: T[] = [];
153→  let buffer = "";
154→
155→  const timeout = setTimeout(() => {
156→    void reader.cancel();
157→  }, timeoutMs);
158→
159→  try {
160→    while (true) {
161→      const { value, done } = await reader.read();
162→      if (done) {
163→        break;
164→      }
165→
166→      buffer += decoder.decode(value, { stream: true });
167→      const segments = buffer.split("\n\n");
168→      buffer = segments.pop() ?? "";
169→
170→      for (const segment of segments) {
171→        const dataLine = segment.split("\n").find((line) => line.startsWith("data: "));
172→        if (!dataLine) {
173→          continue;
174→        }
175→
176→        const event = JSON.parse(dataLine.slice("data: ".length)) as T;
177→        events.push(event);
178→
179→        if (event.type === "error") {
180→          const errorText = (event as { error?: string }).error;
181→          throw new Error(`SSE error event: ${errorText ?? "unknown error"}`);
182→        }
183→
184→        if (event.type === "done") {
185→          return events;
186→        }
187→      }
188→    }
189→  } finally {
190→    clearTimeout(timeout);
191→    reader.releaseLock();
192→  }
193→
194→  return events;
195→}
196→
197→export async function fetchJson<T>(url: string, init?: RequestInit): Promise<T> {
198→  const response = await fetch(url, init);
199→  if (!response.ok) {
200→    const body = await response.text();
201→    throw new Error(`Request failed (${response.status}) ${url}: ${body}`);
202→  }
203→
204→  return (await response.json()) as T;
205→}
